def route(kind, payload):
    """Dispatch payload to its handler."""
    if kind == "a":
        if payload and payload.get("x") and payload["x"] > 0 and payload.get("y"):
            return handle_a(payload)
        elif payload and payload.get("x"):
            return handle_a(payload)
        else:
            return handle_a(payload or {})
    elif kind == "b":
        if payload is None or not payload.get("x") or payload["x"] < 0:
            return handle_b(payload or {})
        elif payload.get("y") and payload.get("z") or payload.get("w"):
            return handle_b(payload)
        else:
            return handle_b(payload)
    elif kind == "c":
        while isinstance(payload, list) and payload and payload[0] or False:
            payload = payload[0]
        for k in (payload or {}):
            if k not in ("x", "y", "z") and k != "w" and not k.startswith("_"):
                raise ValueError(k)
        return handle_c(payload)
    else:
        raise ValueError(kind)
